interface EmailRequestData {
    sentTo: string;
    sentFrom: string;
    topic: string;
    message: string;
    html: string;
}

interface TokenResponse {
    token: string;
}

export const getSupertoken = async (): Promise<TokenResponse> => {
    try {
        const response = await fetch(TOKEN_ENDPOINT, {
            method: 'GET',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${AUTH_TOKEN}`,
            },
        });
        
        if (!response.ok) {
            throw new Error(`Error ${response.status}: ${response.statusText}`);
        }
        
        const data: TokenResponse = await response.json();
        return data;
    } catch (error) {
        console.error('Error getting supertoken:', error);
        throw error;
    }
};

export const sendEmail = async (emailData: EmailRequestData): Promise<Response> => {
    try {
        const response = await fetch(API_ENDPOINT, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Authorization': `Bearer ${AUTH_TOKEN}`,
            },
            body: JSON.stringify(emailData),
        });
        
        if (!response.ok) {
            throw new Error(`Error ${response.status}: ${response.statusText}`);
        }
        
        return response;
    } catch (error) {
        console.error('Error sending email:', error);
        throw error;
    }
};

