/** @jsxImportSource @emotion/react */
import React, { useEffect, useState } from 'react';
import { css, keyframes } from '@emotion/react';
import { CircularProgress } from '@mui/material';
import { withMyTheme } from '../../theme/theme';
import { MainConfig } from '../../../mainConfig/configHelper';
import { isMobile } from '../../theme/isMobile';

const HERO_VIDEO_WEBM = '/images/herobanner_video_optimized.webm';
const HERO_VIDEO_MP4 = '/images/herobanner_video_web.mp4';

const fadeOut = keyframes`
  from {
    opacity: 1;
  }
  to {
    opacity: 0;
    visibility: hidden;
  }
`;

const OverlayStyle = withMyTheme((theme) => css`
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: ${theme.palette.background.default};
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  z-index: 9999;
  transition: opacity 0.5s ease-in-out;
  
  &.loaded {
    animation: ${fadeOut} 0.8s forwards;
  }
`);

const LoaderContainerStyle = withMyTheme(() => css`
  display: flex;
  flex-direction: column;
  align-items: center;
`);

const ProgressStyle = withMyTheme((theme) => css`
  color: ${theme.palette.primary.main};
`);

const LoadingTextStyle = withMyTheme((theme) => css`
  margin-top: 1rem;
  font-family: ${theme.typography.body1.fontFamily};
  color: ${theme.palette.text.secondary};
  font-size: 1rem;
  letter-spacing: 2px;
`);

export const LoadingOverlay: React.FC = () => {
  const [isLoaded, setIsLoaded] = useState(false);
  const imageToLoad = isMobile() ? MainConfig.mainImages.mobileImage : MainConfig.mainImages.desktopImage
  
  useEffect(() => {
    let imageReady = false;
    let videoReady = false;

    const checkAllReady = () => {
      if (imageReady && videoReady) {
        setTimeout(() => {
          setIsLoaded(true);
        }, 500);
      }
    };
    
    const img = new Image();
    img.src = imageToLoad;
    const handleImageLoaded = () => {
      imageReady = true;
      checkAllReady();
    };
    if (img.complete) {
      handleImageLoaded();
    } else {
      img.addEventListener('load', handleImageLoaded);
    }

    const video = document.createElement('video');
    video.preload = 'auto';
    const webmSource = document.createElement('source');
    webmSource.src = HERO_VIDEO_WEBM;
    webmSource.type = 'video/webm';
    const mp4Source = document.createElement('source');
    mp4Source.src = HERO_VIDEO_MP4;
    mp4Source.type = 'video/mp4';
    video.appendChild(webmSource);
    video.appendChild(mp4Source);
    const handleVideoReady = () => {
      videoReady = true;
      checkAllReady();
    };
    if (video.readyState >= 3) {
      handleVideoReady();
    } else {
      video.addEventListener('canplaythrough', handleVideoReady);
    }

    const timeout = setTimeout(() => {
      imageReady = true;
      videoReady = true;
      checkAllReady();
    }, 8000);
    
    return () => {
      img.removeEventListener('load', handleImageLoaded);
      video.removeEventListener('canplaythrough', handleVideoReady);
      clearTimeout(timeout);
    };
  }, [imageToLoad]);
  
  return (
    <div css={OverlayStyle} className={isLoaded ? 'loaded' : ''}>
      <div css={LoaderContainerStyle}>
        <CircularProgress size={'7vh'} thickness={2.5} css={ProgressStyle} />
        <div css={LoadingTextStyle}>LOADING</div>
      </div>
    </div>
  );
};
