export const Rsvp = () => {

    const {t} = useTranslation()

    const [who, setWho] = useState('')
    const [message, setMessage] = useState('')
    const [email, setEmail] = useState('')
    const [emailSent, setEmailSent] = useState(false)
    const [sendEnabled, setSendEnabled] = useState(true)
    const [isSending, setIsSending] = useState(false)

    const rsvpOpen = isTodayBefore(OldConfig.title.exactStartDate);

    const RECIPIENTS = [MainConfig.contact.email1, MainConfig.contact.email2].filter(Boolean);

    const handleSendEmail = async () => {
        if (!validate()) {
            return
        }
        setSendEnabled(false)
        setIsSending(true)

        const htmlContent = createRsvpEmailHtml({ who, email, message });

        try {
            await Promise.all(
                RECIPIENTS.map((recipient) =>
                    sendEmail({
                        sentTo: recipient,
                        sentFrom: email,
                        topic: `RSVP od ${who} — adaimati.pl`,
                        message: message,
                        html: htmlContent,
                    })
                )
            );
            showToast(t('rsvp.sendSuccess'), ToastType.SUCCESS);
            setEmailSent(true)
        } catch (error) {
            showToast(t('rsvp.sendError'), ToastType.ERROR);
            console.error('Could not send email', error);
        } finally {
            setSendEnabled(true)
            setIsSending(false)
        }
    }

    const validate = () => {
        if (who === '' || message === '' || email === '') {
            showToast(t('rsvp.formNotFilledError'), ToastType.ERROR, ToastPosition.BOTTOM_CENTER);
            return false
        }
        return true
    }

    const onWhoChanged = (newWho: string) => {
        setWho(newWho)
    }

    const onMessageChanged = (newMessage: string) => {
        setMessage(newMessage)
    }

    const onEmailChanged = (newEmail: string) => {
        setEmail(newEmail)
    }

    return rsvpOpen ? <Fullscreen id={RSVP_ID} additionalCss={RsvpContent}>
        <div css={RsvpTitle}>{t('rsvp.title')}</div>
        <br/>
            <div css={RsvpDescription}>
                {t('rsvp.description1')}
                <br/><br/>
                {t('rsvp.description2')}
            </div>
            <br/>
            {!emailSent ? <>
                <div css={RsvpInputs}>
                    <MyInput placeholder={t('rsvp.who')}
                             onChange={(value) => onWhoChanged(value)}
                             value={who}
                             additionalCss={RsvpInputText}/>
                    <br/>
                    <MyInput additionalCss={RsvpInputText}
                             multiline
                             rows={3}
                             value={message}
                             placeholder={t('rsvp.message')}
                             onChange={(value) => onMessageChanged(value)} />
                    <br/>
                    <MyInput placeholder={t('rsvp.email')}
                             value={email}
                             type="email"
                             autoComplete="email"
                             onChange={(value) => onEmailChanged(value)}
                             additionalCss={RsvpInputText}/>
                </div>
                <MyButton text={t('rsvp.send')} variant={"contained"} additionalCss={RsvpButton} enabled={sendEnabled} loading={isSending} onClick={handleSendEmail}/>
            </> : <div css={RsvpThankYouTitle} dangerouslySetInnerHTML={{ __html: t('rsvp.thankYou') }}/>}
            <br/>
            {(MainConfig.contact.phone1 || MainConfig.contact.phone2) && (
                <div css={RsvpOurContacts}>
                    {MainConfig.contact.phone1 && (
                        <div css={RsvpOurContact}>
                            {MainConfig.basicInfo.coupleName1} <PhoneNumber phoneNumber={MainConfig.contact.phone1}/>
                        </div>
                    )}
                    {MainConfig.contact.phone2 && (
                        <div css={RsvpOurContact}>
                            {MainConfig.basicInfo.coupleName2} <PhoneNumber phoneNumber={MainConfig.contact.phone2}/>
                        </div>
                    )}
                </div>
            )}
    </Fullscreen> : <></>
}

const PhoneNumber = (props: { phoneNumber: string }) => {
    const callNumber = (phoneNumber: string) => {
        window.location.href = `tel:${phoneNumber}`;
    };

    return <span css={RsvpPhone} onClick={() => callNumber(props.phoneNumber)}>
        {props.phoneNumber}
    </span>
}